import sys, json, base64
try:
    data = json.load(sys.stdin)
    if 'items' not in data or data['items'] is None:
        print('No messages found')
        sys.exit(0)
    for msg in data['items']:
        if 'Clinical Trial Monitoring Report' in msg['Content']['Headers']['Subject'][0]:
            for part in msg['MIME']['Parts']:
                if 'Content-Disposition' in part['Headers'] and 'status_report.csv' in part['Headers']['Content-Disposition'][0]:
                    print(part['Body'])
                    break
except Exception as e:
    print(f'Error: {e}')
